function bubbleSort(a) {
  for (let i = 0; i < a.length; i++) {
    for (let j = 0; j < a.length - 1 - i; j++) {
      if (a[j] > a[j + 1]) {
        const t = a[j];
        a[j] = a[j + 1];
        a[j + 1] = t;
      }
    }
  }
  return a;
}

tests:
const eq = (x, y) => JSON.stringify(x) === JSON.stringify(y);
if (!eq(bubbleSort([5, 2, 4, 6, 1, 3]), [1, 2, 3, 4, 5, 6])) throw new Error('basic');
if (!eq(bubbleSort([]), [])) throw new Error('empty');
if (!eq(bubbleSort([1]), [1])) throw new Error('single');
if (!eq(bubbleSort([3, 3, 1]), [1, 3, 3])) throw new Error('dups');

