function byLastChar(words) {
  return words.slice().sort((a, b) => a[a.length - 1].localeCompare(b[b.length - 1]));
}

tests:
const eq = (x, y) => JSON.stringify(x) === JSON.stringify(y);
if (!eq(byLastChar(['cba', 'abc', 'bca']), ['cba', 'bca', 'abc'])) throw new Error('by last char');
if (!eq(byLastChar(['ax', 'bx', 'c']), ['c', 'ax', 'bx'])) throw new Error('stable ties');
const o = ['yz', 'xy'];
byLastChar(o);
if (!eq(o, ['yz', 'xy'])) throw new Error('must not mutate input');

