function topK(nums, k) {
  return nums.slice().sort((a, b) => b - a).slice(0, k);
}

tests:
const eq = (x, y) => JSON.stringify(x) === JSON.stringify(y);
if (!eq(topK([3, 1, 4, 1, 5, 9, 2], 3), [9, 5, 4])) throw new Error('basic');
if (!eq(topK([1], 5), [1])) throw new Error('k too big');
if (!eq(topK([], 3), [])) throw new Error('empty');
const o = [2, 1, 3];
topK(o, 2);
if (!eq(o, [2, 1, 3])) throw new Error('must not mutate input');

