function minGap(nums) {
  const a = nums.slice().sort((x, y) => x - y);
  let best = Infinity;
  for (let i = 1; i < a.length; i++) {
    if (a[i] - a[i - 1] < best) best = a[i] - a[i - 1];
  }
  return best;
}

tests:
if (minGap([3, 8, 1, 5]) !== 2) throw new Error('basic');
if (minGap([1, 100, 101]) !== 1) throw new Error('close pair at end');
if (minGap([5, 5, 9]) !== 0) throw new Error('equal values');
const o = [10, 3];
minGap(o);
if (JSON.stringify(o) !== JSON.stringify([10, 3])) throw new Error('must not mutate input');
